import { z } from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { View, Text, TextInput, Button, Alert } from 'react-native';

// Schéma de validation
const addressSchema = z.object({
  fullName: z.string().min(3, 'Le nom complet doit contenir au moins 3 caractères'),
  phone: z.string().regex(/^(6|7)[0-9]{8}$/, 'Numéro de téléphone invalide (ex: 612345678)'),
  city: z.string().min(2, 'La ville est requise'),
  address: z.string().min(5, 'L\'adresse doit contenir au moins 5 caractères'),
  postalCode: z.string().optional(),
});

type AddressFormData = z.infer<typeof addressSchema>;

const AddressForm = () => {
  const { control, handleSubmit, formState: { errors, isSubmitting }, setValue } = useForm<AddressFormData>({
    resolver: zodResolver(addressSchema),
    defaultValues: {
      fullName: '',
      phone: '',
      city: '',
      address: '',
      postalCode: '',
    },
  });

  const onSubmit = (data: AddressFormData) => {
    console.log('Données valides :', data);
    Alert.alert('Succès', 'Adresse enregistrée');
  };

  return (
    <View style={{ padding: 16 }}>
      <Text>Nom complet *</Text>
      <TextInput
        placeholder="Jean Dupont"
        onChangeText={(text) => setValue('fullName', text)}
        style={{ borderWidth: 1, borderColor: '#ccc', borderRadius: 8, padding: 10, marginBottom: 8 }}
      />
      {errors.fullName && <Text style={{ color: 'red' }}>{errors.fullName.message}</Text>}

      <Text>Téléphone *</Text>
      <TextInput
        placeholder="612345678"
        keyboardType="phone-pad"
        onChangeText={(text) => setValue('phone', text)}
        style={{ borderWidth: 1, borderColor: '#ccc', borderRadius: 8, padding: 10, marginBottom: 8 }}
      />
      {errors.phone && <Text style={{ color: 'red' }}>{errors.phone.message}</Text>}

      <Text>Ville *</Text>
      <TextInput
        placeholder="Douala"
        onChangeText={(text) => setValue('city', text)}
        style={{ borderWidth: 1, borderColor: '#ccc', borderRadius: 8, padding: 10, marginBottom: 8 }}
      />
      {errors.city && <Text style={{ color: 'red' }}>{errors.city.message}</Text>}

      <Text>Adresse *</Text>
      <TextInput
        placeholder="Rue X, Quartier Y"
        onChangeText={(text) => setValue('address', text)}
        style={{ borderWidth: 1, borderColor: '#ccc', borderRadius: 8, padding: 10, marginBottom: 8 }}
      />
      {errors.address && <Text style={{ color: 'red' }}>{errors.address.message}</Text>}

      <Text>Code postal (optionnel)</Text>
      <TextInput
        placeholder="BP 12345"
        onChangeText={(text) => setValue('postalCode', text)}
        style={{ borderWidth: 1, borderColor: '#ccc', borderRadius: 8, padding: 10, marginBottom: 16 }}
      />

      <Button title="Enregistrer" onPress={handleSubmit(onSubmit)} disabled={isSubmitting} />
    </View>
  );
};

export default AddressForm;
