import React, { useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';

interface DeliveryMethod {
  id: string;
  label: string;
  description: string;
  price: number;
}

const deliveryMethods: DeliveryMethod[] = [
  { id: 'standard', label: 'Standard', description: '3-5 jours ouvrés', price: 2500 },
  { id: 'express', label: 'Express', description: '1-2 jours ouvrés', price: 5000 },
  { id: 'pickup', label: 'Retrait en magasin', description: 'Gratuit - Douala/Yaoundé', price: 0 },
];

interface DeliveryMethodSelectorProps {
  onSelect: (method: DeliveryMethod) => void;
  defaultMethodId?: string;
}

const DeliveryMethodSelector: React.FC<DeliveryMethodSelectorProps> = ({ onSelect, defaultMethodId = 'standard' }) => {
  const [selectedId, setSelectedId] = useState(defaultMethodId);

  const handleSelect = (method: DeliveryMethod) => {
    setSelectedId(method.id);
    onSelect(method);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Mode de livraison</Text>
      {deliveryMethods.map((method) => (
        <TouchableOpacity
          key={method.id}
          style={[styles.option, selectedId === method.id && styles.optionSelected]}
          onPress={() => handleSelect(method)}
        >
          <View style={styles.radioContainer}>
            <View style={[styles.radioOuter, selectedId === method.id && styles.radioOuterSelected]}>
              {selectedId === method.id && <View style={styles.radioInner} />}
            </View>
            <View style={styles.optionContent}>
              <Text style={styles.optionLabel}>{method.label}</Text>
              <Text style={styles.optionDescription}>{method.description}</Text>
            </View>
            <Text style={styles.optionPrice}>
              {method.price === 0 ? 'Gratuit' : `${method.price.toLocaleString()} FCFA`}
            </Text>
          </View>
        </TouchableOpacity>
      ))}
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 16, backgroundColor: '#fff', borderRadius: 12, marginBottom: 16 },
  title: { fontSize: 18, fontWeight: 'bold', marginBottom: 12 },
  option: { paddingVertical: 12, borderBottomWidth: 1, borderBottomColor: '#eee' },
  optionSelected: { backgroundColor: '#f0f7ff', borderRadius: 8 },
  radioContainer: { flexDirection: 'row', alignItems: 'center' },
  radioOuter: { width: 20, height: 20, borderRadius: 10, borderWidth: 2, borderColor: '#ccc', justifyContent: 'center', alignItems: 'center', marginRight: 12 },
  radioOuterSelected: { borderColor: '#0066cc' },
  radioInner: { width: 10, height: 10, borderRadius: 5, backgroundColor: '#0066cc' },
  optionContent: { flex: 1 },
  optionLabel: { fontSize: 16, fontWeight: '500' },
  optionDescription: { fontSize: 12, color: '#666', marginTop: 2 },
  optionPrice: { fontSize: 14, fontWeight: '600', color: '#e67e22' },
});

export default DeliveryMethodSelector;
