import React from 'react';
import { View, Text, FlatList, StyleSheet } from 'react-native';

interface CartItem {
  id: string;
  name: string;
  quantity: number;
  unitPrice: number;
}

interface OrderSummaryProps {
  items: CartItem[];
  deliveryPrice: number;
  taxRate?: number; // TVA par exemple 19.25%
}

const OrderSummary: React.FC<OrderSummaryProps> = ({ items, deliveryPrice, taxRate = 0 }) => {
  const subtotal = items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
  const taxAmount = subtotal * (taxRate / 100);
  const total = subtotal + deliveryPrice + taxAmount;

  const formatCurrency = (amount: number) => `${amount.toLocaleString()} FCFA`;

  const renderItem = ({ item }: { item: CartItem }) => (
    <View style={styles.itemRow}>
      <Text style={styles.itemName}>
        {item.name} × {item.quantity}
      </Text>
      <Text style={styles.itemPrice}>
        {formatCurrency(item.quantity * item.unitPrice)}
      </Text>
    </View>
  );

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Récapitulatif de la commande</Text>

      <FlatList
        data={items}
        renderItem={renderItem}
        keyExtractor={(item) => item.id}
        scrollEnabled={false}
      />

      <View style={styles.divider} />

      <View style={styles.row}>
        <Text>Sous-total</Text>
        <Text>{formatCurrency(subtotal)}</Text>
      </View>

      {taxRate > 0 && (
        <View style={styles.row}>
          <Text>TVA ({taxRate}%)</Text>
          <Text>{formatCurrency(taxAmount)}</Text>
        </View>
      )}

      <View style={styles.row}>
        <Text>Livraison</Text>
        <Text>{deliveryPrice === 0 ? 'Gratuit' : formatCurrency(deliveryPrice)}</Text>
      </View>

      <View style={[styles.row, styles.totalRow]}>
        <Text style={styles.totalLabel}>Total</Text>
        <Text style={styles.totalAmount}>{formatCurrency(total)}</Text>
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 16, backgroundColor: '#fff', borderRadius: 12, marginVertical: 8 },
  title: { fontSize: 18, fontWeight: 'bold', marginBottom: 16 },
  itemRow: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 8 },
  itemName: { flex: 1, fontSize: 14 },
  itemPrice: { fontSize: 14, fontWeight: '500' },
  divider: { height: 1, backgroundColor: '#eee', marginVertical: 12 },
  row: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 6 },
  totalRow: { marginTop: 8, paddingTop: 12, borderTopWidth: 1, borderTopColor: '#ddd' },
  totalLabel: { fontSize: 18, fontWeight: 'bold' },
  totalAmount: { fontSize: 20, fontWeight: 'bold', color: '#e67e22' },
});

export default OrderSummary;
